def initialize(url = nil, options = nil)
      options = ConnectionOptions.from(options)

      if url.is_a?(Hash) || url.is_a?(ConnectionOptions)
        options = Utils.deep_merge(options, url)
        url     = options.url
      end

      @parallel_manager = nil
      @headers = Utils::Headers.new
      @params  = Utils::ParamsHash.new
      @options = options.request
      @ssl = options.ssl
      @default_parallel_manager = options.parallel_manager
      @manual_proxy = nil

      @builder = options.builder || begin
        # pass an empty block to Builder so it doesn't assume default middleware
        options.new_builder(block_given? ? proc { |b| } : nil)
      end

      self.url_prefix = url || 'http:/'

      @params.update(options.params)   if options.params
      @headers.update(options.headers) if options.headers

      initialize_proxy(url, options)

      yield(self) if block_given?

      @headers[:user_agent] ||= USER_AGENT
    end

def attempt_oembed
    service         = FetchOEmbedService.new
    url_domain      = Addressable::URI.parse(@url).normalized_host
    cached_endpoint = Rails.cache.read("oembed_endpoint:#{url_domain}")

    embed   = service.call(@url, cached_endpoint: cached_endpoint) unless cached_endpoint.nil?
    embed ||= service.call(@url, html: html) unless html.nil?

    return false if embed.nil?

    url = Addressable::URI.parse(service.endpoint_url)

    @card.type          = embed[:type]
    @card.title         = embed[:title]         || ''
    @card.author_name   = embed[:author_name]   || ''
    @card.author_url    = embed[:author_url].present? ? (url + embed[:author_url]).to_s : ''
    @card.provider_name = embed[:provider_name] || ''
    @card.provider_url  = embed[:provider_url].present? ? (url + embed[:provider_url]).to_s : ''
    @card.width         = 0
    @card.height        = 0

    case @card.type
    when 'link'
      @card.image_remote_url = (url + embed[:thumbnail_url]).to_s if embed[:thumbnail_url].present?
    when 'photo'
      return false if embed[:url].blank?

      @card.embed_url        = (url + embed[:url]).to_s

def initialize(multiplex)
        @multiplex = multiplex
        @schema = multiplex.schema
        @steps_queue = []
        @runtime_type_at = {}.compare_by_identity
        @static_type_at = {}.compare_by_identity
        @finalizers = nil
        @selected_operation = nil
        @dataloader = multiplex.context[:dataloader] ||= @schema.dataloader_class.new
        @resolves_lazies = @schema.resolves_lazies?
        @input_values = Hash.new do |h, query|
          h[query] = InputValues.new(query, self)
        end.compare_by_identity

        @runtime_directives = nil
        @schema.directives.each do |name, dir_class|
          if dir_class.runtime? && name != "include" && name != "skip"
            @runtime_directives ||= {}
            @runtime_directives[dir_class.graphql_name] = dir_class
          end
        end

        if @runtime_directives.nil?
          @uses_runtime_directives = false
          @runtime_directives = EmptyObjects::EMPTY_HASH
        else
          @uses_runtime_directives = true
        end

        @lazy_cache = resolves_lazies ? {}.compare_by_identity : nil
        @authorizes_cache = Hash.new do |h, query_context|
          h[query_context] = {}.compare_by_identity
        end.compare_by_identity
      end

def initialize(io, env=nil)
      @io = io
      @to_io = io.to_io
      @io_buffer = IOBuffer.new
      @proto_env = env
      @env = env&.dup

      @parser = HttpParser.new
      @parsed_bytes = 0
      @read_header = true
      @read_proxy = false
      @ready = false

      @body = nil
      @body_read_start = nil
      @buffer = nil
      @tempfile = nil

      @timeout_at = nil

      @requests_served = 0
      @hijacked = false

      @http_content_length_limit = nil
      @http_content_length_limit_exceeded = nil
      @allow_underscore_headers = true
      @error_status_code = nil

      @peerip = nil
      @peer_family = nil
      @listener = nil
      @remote_addr_header = nil
      @expect_proxy_proto = false

      @body_remain = 0

      @in_last_chunk = false

      # need unfrozen ASCII-8BIT, +'' is UTF-8
      @read_buffer = String.new # rubocop: disable Performance/UnfreezeString
    end
